-- V15: full CPCB battery-recycler master data — all 553 rows from CPCB's complete public
-- registry pull (cpcb_battery_recyclers_COMPLETE_2026-07-08.csv, 41-column contract, see V14),
-- ingested and verified via POST /api/v1/cpcb-recyclers/ingest, then captured here as a migration
-- so a fresh environment has the full directory without a manual ingest step. Supersedes V13's
-- 13-row sample: V13 stays as history (Flyway migrations are immutable once applied), but its
-- 12 rows that had a real cpcb_id get upserted with full data below (same cpcb_id, same row,
-- richer columns), and its one truly orphaned row (Attero, no source id captured in that sample)
-- is deleted here since the row below (cpcb_id 166) is the real, complete Attero record.
--
-- Values verbatim from a live ingest run against this exact CSV, not hand-retyped — that's the
-- only way rows with CPCB's own source-data garbage (space-separated dates, out-of-bounds
-- lat/lng nulled per V14''s ingestion validation, the "TESTING P"/id 1003 placeholder row) end up
-- byte-identical to what the tested Kotlin ingestion pipeline actually produces, instead of a
-- second hand-written implementation that could quietly diverge from it.
--
-- Composite scores are still NOT seeded here (derived/recomputable — CpcbRecyclerScoringBackfillRunner
-- backfills them on startup for any recycler without one, same as V13's approach). A future CPCB
-- re-pull goes through the ingest endpoint as normal, not another migration like this one — this
-- is a one-time "make master data self-contained" catch-up, not the standing update mechanism.
SET search_path TO eprid;

-- V13's one row with no source cpcb_id at all — a partial-capture artifact from the old 13-row
-- sample, now fully superseded by the real, complete row in this migration. Cascades to delete
-- its 3 stale authorization rows too (cpcb_recycler_authorizations has ON DELETE CASCADE).
DELETE FROM cpcb_recyclers WHERE cpcb_id IS NULL;

-- Clear any pre-existing authorization rows for the recyclers this migration is about to
-- (re)insert authorizations for — makes this migration safe to layer onto an environment that
-- already ran a live ingest of the same data (upsert-by-cpcb_id above would otherwise pair with
-- a blind INSERT below and duplicate every authorization row).
DELETE FROM cpcb_recycler_authorizations WHERE recycler_id IN (
    SELECT id FROM cpcb_recyclers WHERE cpcb_id IS NOT NULL
);

